import axios from 'axios'

// Mock axios before importing auth module
vi.mock('@/api/axios', () => {
  return {
    default: {
      post: vi.fn(),
      get: vi.fn(),
      put: vi.fn(),
      delete: vi.fn(),
      patch: vi.fn(),
      defaults: { baseURL: '/api' },
      interceptors: {
        request: { use: vi.fn(), handlers: [] },
        response: { use: vi.fn(), handlers: [] },
      },
    },
  }
})

import api from '@/api/axios'
import { login, register } from '@/api/auth'

describe('Auth API', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  describe('login', () => {
    it('should call POST /auth/login with username and password', async () => {
      const mockResponse = { data: { token: 'jwt-token', expiresIn: 86400 } }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      const result = await login('testuser', 'password123')

      expect(api.post).toHaveBeenCalledWith('/auth/login', {
        username: 'testuser',
        password: 'password123',
      })
      expect(result).toEqual({ token: 'jwt-token', expiresIn: 86400 })
    })

    it('should return token and expiresIn fields', async () => {
      const mockResponse = { data: { token: 'abc123', expiresIn: 86400 } }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      const result = await login('user', 'pass')

      expect(result).toHaveProperty('token')
      expect(result).toHaveProperty('expiresIn')
      expect(typeof result.token).toBe('string')
      expect(typeof result.expiresIn).toBe('number')
    })
  })

  describe('register', () => {
    it('should call POST /auth/register with registration data', async () => {
      const registerData = {
        username: 'newuser',
        password: 'password123',
        displayName: 'New User',
      }
      const mockResponse = {
        data: { id: 1, username: 'newuser', displayName: 'New User' },
      }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      const result = await register(registerData)

      expect(api.post).toHaveBeenCalledWith('/auth/register', registerData)
      expect(result).toEqual({
        id: 1,
        username: 'newuser',
        displayName: 'New User',
      })
    })

    it('should return UserResponse with id, username, displayName', async () => {
      const mockResponse = {
        data: { id: 42, username: 'alice', displayName: 'Alice' },
      }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      const result = await register({
        username: 'alice',
        password: 'pass1234',
        displayName: 'Alice',
      })

      expect(result).toHaveProperty('id')
      expect(result).toHaveProperty('username')
      expect(result).toHaveProperty('displayName')
    })
  })
})

